5	
6	//! Typed-API host-closure smoke test.
7	//!
8	//! Drives the typed `#[cuda_module]` launch path with a generic kernel that
9	//! takes a closure. This exercises the kernel-boundary ABI fix that lets the
10	//! typed path push the closure as a single byval `.param` and have the
11	//! backend emit a single matching `.param` declaration. Before the fix this
12	//! example only worked through the call-site `cuda_launch!` macro because
13	//! that path pushed each capture individually; the typed API kept the
14	//! closure intact and mis-matched the backend's flattened ABI.
15	//!
16	//! Build and run with:
17	//!   cargo oxide run host_closure
18	//!
19	//! ## What it covers
20	//!
21	//! 1. Generic kernel with `Fn` trait bound: `fn map<T, F: Fn(T) -> T + Copy>(...)`
22	//! 2. Closures with 0, 1, 2, 3, 4 captures.
23	//! 3. Type inference of `F` at the call site (`module.map::<f32, _>(...)`).
24	//! 4. The closure is passed as a single byval struct — no per-capture flattening
25	//!    on either side.
26	//! 5. Equivalent coverage through sync and async typed and untyped launch paths.
27	//! 6. A where-clause `Fn` bound and layout-sensitive captures.
28	//! 7. `FnMut` and `FnOnce` trait bounds, so the device-side dispatch path is
29	//!    exercised for all three closure traits.
30	//! 8. Both reordered (default Rust repr, mixed-size fields) and identity-order
31	//!    (`#[repr(C)]`) struct captures.
32	
33	use cuda_async::device_operation::DeviceOperation;
34	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
35	use cuda_device::{DisjointSlice, kernel, thread};
36	use cuda_host::{cuda_launch, cuda_launch_async, cuda_module, load_kernel_module};
37	
38	#[derive(Clone, Copy)]
39	struct MixedCapture {
40	    small: u8,
41	    wide: f64,
42	    scale: f32,
43	}
44	
45	/// Same field set as [`MixedCapture`], but `#[repr(C)]` pins the layout to
46	/// declaration order (no rustc field reordering). The closure-layout fix has
47	/// to handle both the reordered and the identity-order cases, so we exercise
48	/// the identity path explicitly.
49	#[derive(Clone, Copy)]
50	#[repr(C)]
51	struct ReprCMixed {
52	    small: u8,
53	    wide: f64,
54	    scale: f32,
55	}
56	
57	// =============================================================================
58	// CLOSURE-ACCEPTING GENERIC KERNELS
59	// =============================================================================
60	#[cuda_module]
61	mod kernels {
62	    use super::*;
63	
64	    /// Generic map kernel — applies a function to each element.
65	    ///
66	    /// `F` is bound to the closure's anonymous type at the call site via
67	    /// the typed API's turbofish placeholder (`module.map::<f32, _>(...)`).
68	    /// The closure value itself is pushed as one byval kernel argument; the
69	    /// device reads it back as `F` and calls `f(input[idx])` on each thread.
70	    #[kernel]
71	    pub fn map<T: Copy, F: Fn(T) -> T + Copy>(f: F, input: &[T], mut out: DisjointSlice<T>) {
72	        let idx = thread::index_1d();
73	        let idx_raw = idx.get();
74	        if let Some(out_elem) = out.get_mut(idx) {
75	            *out_elem = f(input[idx_raw]);
76	        }
77	    }
78	
79	    /// Closure-generic kernel with a const parameter that cannot be inferred
80	    /// from its runtime arguments. This exercises explicit generic forwarding
81	    /// in both low-level launch macros.
82	    #[kernel]
83	    pub fn map_with_const<F, const OFFSET: u32>(f: F, input: &[u32], mut out: DisjointSlice<u32>)
84	    where
85	        F: Fn(u32) -> u32 + Copy,
86	    {
87	        let idx = thread::index_1d();
88	        let idx_raw = idx.get();
89	        if let Some(out_elem) = out.get_mut(idx) {
90	            *out_elem = f(input[idx_raw]) + OFFSET;
91	        }
92	    }
93	
94	    #[kernel]
95	    pub fn map_where<T, F>(f: F, input: &[T], mut out: DisjointSlice<T>)
96	    where
97	        T: Copy,
98	        F: Fn(T) -> T + Copy,
99	    {
100	        let idx = thread::index_1d();
101	        let idx_raw = idx.get();
102	        if let Some(out_elem) = out.get_mut(idx) {
103	            *out_elem = f(input[idx_raw]);
104	        }
105	    }
106	
107	    /// Same as [`map`] but with a `FnMut` trait bound, so the device-side
108	    /// dispatch goes through `<F as FnMut>::call_mut` instead of `Fn::call`.
109	    /// The closure is `Copy`, so each thread mutates its own register-resident
110	    /// copy of the closure environment.
111	    #[kernel]
112	    pub fn map_mut<T, F>(mut f: F, input: &[T], mut out: DisjointSlice<T>)
113	    where
114	        T: Copy,
115	        F: FnMut(T) -> T + Copy,
116	    {
117	        let idx = thread::index_1d();
118	        let idx_raw = idx.get();
119	        if let Some(out_elem) = out.get_mut(idx) {
120	            *out_elem = f(input[idx_raw]);
121	        }
122	    }
123	
124	    /// Same as [`map`] but with a `FnOnce` trait bound, so the device-side
125	    /// dispatch goes through `<F as FnOnce>::call_once` (which consumes the
126	    /// closure). The `Copy` bound lets the kernel re-invoke `call_once` per
127	    /// thread on a freshly-copied closure rather than running it exactly once.
128	    #[kernel]
129	    pub fn map_once<T, F>(f: F, input: &[T], mut out: DisjointSlice<T>)
130	    where
131	        T: Copy,
132	        F: FnOnce(T) -> T + Copy,
133	    {
134	        let idx = thread::index_1d();
135	        let idx_raw = idx.get();
136	        if let Some(out_elem) = out.get_mut(idx) {
137	            *out_elem = f(input[idx_raw]);
138	        }
139	    }
140	}
141	
142	fn verify_output(
143	    label: &str,
144	    output: &[f32],
145	    input: &[f32],
146	    tolerance: f32,
147	    expected: impl Fn(f32) -> f32,
148	    failed: &mut bool,
149	) {
150	    let errors = output
151	        .iter()
152	        .zip(input)
153	        .filter(|(got, x)| (**got - expected(**x)).abs() > tolerance)
154	        .count();
155	
156	    if errors == 0 {
157	        println!("  ✓ SUCCESS: {label}");
158	    } else {
159	        println!("  ✗ FAILED: {label}: {errors} errors");
160	        *failed = true;
161	        for (i, (&got, &x)) in output.iter().zip(input).take(5).enumerate() {
162	            let expected = expected(x);
163	            if (got - expected).abs() > tolerance {
164	                println!("    [{i}]: got {got}, expected {expected}");
165	            }
166	        }
167	    }
168	}
169	
170	// =============================================================================
171	// HOST CODE
172	// =============================================================================
173	
174	fn main() -> Result<(), Box<dyn std::error::Error>> {
175	    println!("=== Typed Closure Kernel Test ===\n");
176	
177	    let ctx = CudaContext::new(0)?;
178	    let stream = ctx.default_stream();
179	
180	    const N: usize = 1024;
181	    let input_data: Vec<f32> = (0..N).map(|i| i as f32).collect();
182	
183	    let input_dev = DeviceBuffer::from_host(&stream, &input_data)?;
184	    let mut output_dev: DeviceBuffer<f32>;
185	
186	    let module = load_kernel_module(&ctx, "host_closure")
187	        .map_err(|err| format!("failed to load host_closure kernel module: {err}"))?;
188	    let typed_module = kernels::from_module(module.clone())
189	        .map_err(|err| format!("failed to initialize typed host_closure module: {err}"))?;
190	    use kernels::*;
191	
192	    let mut failed = false;
193	
194	    macro_rules! run_launch_matrix {
195	        (
196	            $label:literal,
197	            $kernel:path,
198	            $typed_method:ident,
199	            $typed_async_method:ident,
200	            $closure:expr,
201	            $expected:expr,
202	            $tolerance:expr
203	        ) => {{
204	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
205	            // SAFETY: closure-then-slices matches every kernel this matrix
206	            // launches (closure env, input slice, output slice); both buffers
207	            // are live DeviceBuffers and the closure's captures are
208	            // host-accessible via HMM.
209	            unsafe {
210	                cuda_launch! {
211	                    kernel: $kernel,
212	                    stream: stream,
213	                    module: module,
214	                    config: LaunchConfig::for_num_elems(N as u32),
215	                    args: [$closure, slice(input_dev), slice_mut(output_dev)]
216	                }
217	            }?;
218	            let output_host = output_dev.to_host_vec(&stream)?;
219	            verify_output(
220	                concat!("cuda_launch ", $label),
221	                &output_host,
222	                &input_data,
223	                $tolerance,
224	                $expected,
225	                &mut failed,
226	            );
227	
228	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
229	            typed_module.$typed_method::<f32, _>(
230	                stream.as_ref(),
231	                LaunchConfig::for_num_elems(N as u32),
232	                $closure,
233	                &input_dev,
234	                &mut output_dev,
235	            )?;
236	            let output_host = output_dev.to_host_vec(&stream)?;
237	            verify_output(
238	                concat!("typed launch ", $label),
239	                &output_host,
240	                &input_data,
241	                $tolerance,
242	                $expected,
243	                &mut failed,
244	            );
245	
246	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
247	            cuda_launch_async! {
248	                kernel: $kernel,
249	                module: module,
250	                config: LaunchConfig::for_num_elems(N as u32),
251	                args: [$closure, slice(input_dev), slice_mut(output_dev)]
252	            }
253	            .sync_on(&stream)?;
254	            let output_host = output_dev.to_host_vec(&stream)?;
255	            verify_output(
256	                concat!("cuda_launch_async ", $label),
257	                &output_host,
258	                &input_data,
259	                $tolerance,
260	                $expected,
261	                &mut failed,
262	            );
263	
264	            output_dev = DeviceBuffer::<f32>::zeroed(&stream, N)?;
265	            typed_module
266	                .$typed_async_method::<f32, _>(
267	                    LaunchConfig::for_num_elems(N as u32),
268	                    $closure,
269	                    &input_dev,
270	                    &mut output_dev,
271	                )?
272	                .sync_on(&stream)?;
273	            let output_host = output_dev.to_host_vec(&stream)?;
274	            verify_output(
275	                concat!("typed async launch ", $label),
276	                &output_host,
277	                &input_data,
278	                $tolerance,
279	                $expected,
280	                &mut failed,
281	            );
282	        }};
283	    }
284	
285	    // =========================================================================
286	    // TEST 1: Closure with single capture
287	    // =========================================================================
288	    println!("Test 1: Single capture (scale by factor)");
289	    {
290	        let factor = 2.5f32;
291	        println!("  factor = {}", factor);
292	        println!("  N = {}", N);
293	
294	        run_launch_matrix!(
295	            "single capture",
296	            map::<f32, _>,
297	            map,
298	            map_async,
299	            move |x: f32| x * factor,
300	            |x| x * factor,
301	            1e-5
302	        );
303	        println!();
304	    }
305	
306	    // =========================================================================
307	    // TEST 2: Closure with multiple captures
308	    // =========================================================================
309	    println!("Test 2: Multiple captures (affine transform)");
310	    {
311	        let scale = 2.0f32;
312	        let offset = 10.0f32;
313	        println!("  scale = {}, offset = {}", scale, offset);
314	
315	        run_launch_matrix!(
316	            "multiple captures",
317	            map::<f32, _>,
318	            map,
319	            map_async,
320	            move |x: f32| x * scale + offset,
321	            |x| x * scale + offset,
322	            1e-5
323	        );
324	        println!();
325	    }
326	
327	    // =========================================================================
328	    // TEST 3: Zero-capture closure (inline constant)
329	    // =========================================================================
330	    println!("Test 3: Zero captures (double each element)");
331	    {
332	        run_launch_matrix!(
333	            "zero-capture closure",
334	            map::<f32, _>,
335	            map,
336	            map_async,
337	            |x: f32| x * 2.0,
338	            |x| x * 2.0,
339	            1e-5
340	        );
341	        println!();
342	    }
343	
344	    // =========================================================================
345	    // TEST 4: Closure with 3 captures (polynomial transform)
346	    // =========================================================================
347	    println!("Test 4: Three captures (polynomial: a*x^2 + b*x + c)");
348	    {
349	        let a = 0.5f32;
350	        let b = 2.0f32;
351	        let c = 1.0f32;
352	        println!("  a = {}, b = {}, c = {}", a, b, c);
353	
354	        run_launch_matrix!(
355	            "three captures",
356	            map::<f32, _>,
357	            map,
358	            map_async,
359	            move |x: f32| a * x * x + b * x + c,
360	            |x| a * x * x + b * x + c,
361	            1e-3
362	        );
363	        println!();
364	    }
365	
366	    // =========================================================================
367	    // TEST 5: Closure with 4 captures (to ensure arbitrary count works)
368	    // =========================================================================
369	    println!("Test 5: Four captures (weighted sum: w1*x + w2 + w3*w4)");
370	    {
371	        let w1 = 3.0f32;
372	        let w2 = 5.0f32;
373	        let w3 = 2.0f32;
374	        let w4 = 7.0f32;
375	        println!("  w1 = {}, w2 = {}, w3 = {}, w4 = {}", w1, w2, w3, w4);
376	
377	        run_launch_matrix!(
378	            "four captures",
379	            map::<f32, _>,
380	            map,
381	            map_async,
382	            move |x: f32| w1 * x + w2 + w3 * w4,
383	            |x| w1 * x + w2 + w3 * w4,
384	            1e-3
385	        );
386	        println!();
387	    }
388	
389	    // =========================================================================
390	    // TEST 6: where-clause Fn bound
391	    // =========================================================================
392	    println!("Test 6: where-clause Fn bound");
393	    {
394	        let scale = 1.5f32;
395	        let bias = 4.0f32;
396	        println!("  scale = {}, bias = {}", scale, bias);
397	
398	        run_launch_matrix!(
399	            "where-clause Fn bound",
400	            map_where::<f32, _>,
401	            map_where,
402	            map_where_async,
403	            move |x: f32| x * scale - bias,
404	            |x| x * scale - bias,
405	            1e-5
406	        );
407	        println!();
408	    }
409	
410	    // =========================================================================
411	    // TEST 7: mixed-size captures
412	    // =========================================================================
413	    println!("Test 7: mixed-size captures");
414	    {
415	        let small = 7u8;
416	        let scale = 1.25f32;
417	        let wide = 3.5f64;
418	        println!("  small = {}, scale = {}, wide = {}", small, scale, wide);
419	
420	        run_launch_matrix!(
421	            "mixed-size captures",
422	            map::<f32, _>,
423	            map,
424	            map_async,
425	            move |x: f32| x * scale + wide as f32 + small as f32,
426	            |x| x * scale + wide as f32 + small as f32,
427	            1e-5
428	        );
429	        println!();
430	    }
431	
432	    // =========================================================================
433	    // TEST 8: struct capture with internal padding
434	    // =========================================================================
435	    println!("Test 8: struct capture with internal padding");
436	    {
437	        let mixed = MixedCapture {
438	            small: 9,
439	            wide: 2.25,
440	            scale: 0.75,
441	        };
442	        println!(
443	            "  small = {}, scale = {}, wide = {}",
444	            mixed.small, mixed.scale, mixed.wide
445	        );
446	
447	        run_launch_matrix!(
448	            "struct capture with internal padding",
449	            map::<f32, _>,
450	            map,
451	            map_async,
452	            move |x: f32| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
453	            |x| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
454	            1e-5
455	        );
456	        println!();
457	    }
458	
459	    // =========================================================================
460	    // TEST 9: non-move reference captures
461	    // =========================================================================
462	    //
463	    // NOTE: this case relies on Heterogeneous Memory Management. Without
464	    // `move`, the closure environment holds `&f32` pointers into the host
465	    // stack frame of `main`; the GPU dereferences those pointers at kernel
466	    // entry. Working configurations need an HMM-capable GPU (sm_75+ on
467	    // Linux) with HMM enabled in the driver. On systems without HMM this
468	    // surfaces as `CUDA_ERROR_ILLEGAL_ADDRESS` from the launch, which the
469	    // smoketest's `verdict_standard` correctly flags as FAIL.
470	    println!("Test 9: non-move reference captures");
471	    {
472	        let scale = 0.5f32;
473	        let bias = 8.0f32;
474	        println!("  scale = {}, bias = {}", scale, bias);
475	        println!("  captures are borrowed by the closure environment");
476	
477	        run_launch_matrix!(
478	            "non-move reference captures",
479	            map::<f32, _>,
480	            map,
481	            map_async,
482	            |x: f32| x * scale + bias,
483	            |x| x * scale + bias,
484	            1e-5
485	        );
486	        println!();
487	    }
488	
489	    // =========================================================================
490	    // TEST 10: FnMut bound — different device-side dispatch from Fn
491	    // =========================================================================
492	    println!("Test 10: FnMut bound (multi-capture)");
493	    {
494	        let scale = 1.5f32;
495	        let offset = 6.0f32;
496	        println!("  scale = {}, offset = {}", scale, offset);
497	
498	        run_launch_matrix!(
499	            "FnMut bound, multi-capture",
500	            map_mut::<f32, _>,
501	            map_mut,
502	            map_mut_async,
503	            move |x: f32| x * scale + offset,
504	            |x| x * scale + offset,
505	            1e-5
506	        );
507	        println!();
508	    }
509	
510	    // =========================================================================
511	    // TEST 11: FnOnce bound — call_once dispatch with Copy
512	    // =========================================================================
513	    println!("Test 11: FnOnce bound (multi-capture, Copy closure)");
514	    {
515	        let weight = 2.25f32;
516	        let intercept = 12.5f32;
517	        println!("  weight = {}, intercept = {}", weight, intercept);
518	
519	        run_launch_matrix!(
520	            "FnOnce bound, multi-capture",
521	            map_once::<f32, _>,
522	            map_once,
523	            map_once_async,
524	            move |x: f32| x * weight + intercept,
525	            |x| x * weight + intercept,
526	            1e-5
527	        );
528	        println!();
529	    }
530	
531	    // =========================================================================
532	    // TEST 12: #[repr(C)] struct capture (identity-order layout)
533	    // =========================================================================
534	    // Counterpart to test 8: the layout fix has to handle both the reordered
535	    // case (default Rust repr, fields packed by size) and the identity-order
536	    // case (`#[repr(C)]`, fields kept in declaration order). The closure
537	    // body is the same as test 8 so the expected output is comparable.
538	    println!("Test 12: #[repr(C)] struct capture (identity-order layout)");
539	    {
540	        let mixed = ReprCMixed {
541	            small: 9,
542	            wide: 2.25,
543	            scale: 0.75,
544	        };
545	        println!(
546	            "  small = {}, scale = {}, wide = {}",
547	            mixed.small, mixed.scale, mixed.wide
548	        );
549	
550	        run_launch_matrix!(
551	            "repr(C) struct capture",
552	            map::<f32, _>,
553	            map,
554	            map_async,
555	            move |x: f32| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
556	            |x| x * mixed.scale + mixed.wide as f32 + mixed.small as f32,
557	            1e-5
558	        );
559	        println!();
560	    }
561	
562	    // =========================================================================
563	    // TEST 13: Closure type inference plus an explicit const argument
564	    // =========================================================================
565	    println!("Test 13: closure plus const-generic specialization");
566	    {
567	        let input: Vec<u32> = (0..N as u32).collect();
568	        let input_dev_u32 = DeviceBuffer::from_host(&stream, &input)?;
569	        let factor = 3u32;
570	
571	        let mut output_4 = DeviceBuffer::<u32>::zeroed(&stream, N)?;
572	        unsafe {
573	            cuda_launch! {
574	                kernel: kernels::map_with_const::<_, 4>,
575	                stream: stream,
576	                module: module,
577	                config: LaunchConfig::for_num_elems(N as u32),
578	                args: [move |x: u32| x * factor, slice(input_dev_u32), slice_mut(output_4)]
579	            }
580	        }?;
581	        let result_4 = output_4.to_host_vec(&stream)?;
582	        assert!((0..N).all(|i| result_4[i] == input[i] * factor + 4));
583	
584	        let mut output_8 = DeviceBuffer::<u32>::zeroed(&stream, N)?;
585	        cuda_launch_async! {
586	            kernel: kernels::map_with_const::<_, 8>,
587	            module: module,
588	            config: LaunchConfig::for_num_elems(N as u32),
589	            args: [move |x: u32| x * factor, slice(input_dev_u32), slice_mut(output_8)]
590	        }
591	        .sync_on(&stream)?;
592	        let result_8 = output_8.to_host_vec(&stream)?;
593	        assert!((0..N).all(|i| result_8[i] == input[i] * factor + 8));
594	
595	        println!("  ✓ SUCCESS: sync and async launch macros forwarded OFFSET");
596	    }
597	
598	    println!("=== All Tests Complete ===");
599	    if failed {
600	        Err("one or more host_closure tests failed".into())
601	    } else {
602	        Ok(())
603	    }
604	}
